import React from 'react';
import { FaSignOutAlt } from 'react-icons/fa';

// Minimal, clean header: App name on the left, Logout button on the right
const Navbar = ({ user, onLogout }) => {
  return (
    <nav
      className="fixed top-0 left-0 right-0 z-50 bg-white/90 backdrop-blur-lg border-b border-gray-200"
      style={{ boxShadow: '0 4px 20px rgba(0,0,0,0.06)' }}
      role="navigation"
      aria-label="Top navigation"
    >
      <div className="container mx-auto px-5">
        <div className="flex items-center justify-between h-16">
          {/* App Name */}
          <div className="flex items-center min-w-0">
            <span
              className="truncate select-none"
              style={{
                fontWeight: 800,
                fontSize: '1.25rem',
                letterSpacing: '-0.02em',
                background: 'linear-gradient(90deg, #2563eb, #14b8a6)',
                WebkitBackgroundClip: 'text',
                backgroundClip: 'text',
                color: 'transparent'
              }}
            >
              Helio
            </span>
          </div>

          {/* Logout button (only when logged in) */}
          {user && onLogout && (
            <button
              onClick={onLogout}
              title="Logout"
              className="relative inline-flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium text-gray-700 transition-all"
              style={{
                background: 'linear-gradient(180deg, #ffffff, #f8fafc)',
                border: '1px solid #e5e7eb',
                boxShadow: '0 6px 16px rgba(2,6,23,0.06)'
              }}
            >
              <FaSignOutAlt className="text-gray-600" />
              <span>Logout</span>
            </button>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
